# Define tier qualification criteria as dictionaries
# This is the 'data as policy' pattern — criteria live in config, not code
tier_criteria = {
    'CONSERVATIVE': {
        'min_account_age_days': 0,
        'max_account_age_days': 180,
        'description': 'New accounts: under 6 months tenure'
    },
    'STANDARD': {
        'min_account_age_days': 181,
        'max_account_age_days': 730,
        'description': 'Established accounts: 6 months to 2 years'
    },
    'ADVANCED': {
        'min_account_age_days': 731,
        'max_account_age_days': 9999,
        'description': 'Veteran accounts: over 2 years tenure'
    }
}

# Apply tier assignment using the dictionary criteria
def assign_tier(account_age_days, criteria_dict):
    for tier_name, criteria in criteria_dict.items():
        if criteria['min_account_age_days'] <= account_age_days <= criteria['max_account_age_days']:
            return tier_name
    return 'CONSERVATIVE'  # Safe default

gold_users['assigned_tier'] = gold_users['account_age_days'].apply(
    lambda age: assign_tier(age, tier_criteria)
)

# Count customers in each tier
tier_counts = gold_users['assigned_tier'].value_counts()
tier_pcts = tier_counts / len(gold_users) * 100

print("Tier distribution under proposed segmentation:")
for tier in ['CONSERVATIVE', 'STANDARD', 'ADVANCED']:
    count = tier_counts.get(tier, 0)
    pct = tier_pcts.get(tier, 0)
    print(f"  {tier:20s}: {count:>10,} customers ({pct:.1f}%)")

# Fee structures — three policy options
fee_structures = {
    'FLAT': {'CONSERVATIVE': 5.0, 'STANDARD': 5.0, 'ADVANCED': 5.0},
    'TIERED_MODERATE': {'CONSERVATIVE': 3.0, 'STANDARD': 5.0, 'ADVANCED': 12.0},
    'TIERED_AGGRESSIVE': {'CONSERVATIVE': 2.0, 'STANDARD': 6.0, 'ADVANCED': 18.0}
}

print(f"{'Fee Structure':>22} {'Monthly Revenue':>18} {'Meets $8M Target?':>20}")
print("-" * 65)

for structure_name, fees in fee_structures.items():
    monthly_revenue = 0
    for tier_name, fee in fees.items():
        count = tier_counts.get(tier_name, 0)
        monthly_revenue += count * fee

    meets_target = 'YES' if monthly_revenue >= 8_000_000 else 'NO'
    print(f"{structure_name:>22} ${monthly_revenue:>16,.0f} {meets_target:>20}")

