TIER_CONFIG = {
    'LOW': {
        'max_leverage': 4.0,
        'monthly_fee': 12.00,
        'can_trade_options': True,
        'fee_waiver': False
    },
    'MEDIUM': {
        'max_leverage': 2.0,
        'monthly_fee': 5.00,
        'can_trade_options': True,
        'fee_waiver': False
    },
    'HIGH': {
        'max_leverage': 1.0,
        'monthly_fee': 0.00,
        'can_trade_options': False,
        'fee_waiver': True
    }
}

def _get_tier(account_age_days, credit_score, margin_utilization):
    if credit_score >= 720 and account_age_days >= 365 and margin_utilization <= 0.50:
        return 'LOW'
    if credit_score >= 640 and account_age_days >= 90:
        return 'MEDIUM'
    return 'HIGH'

def customer_risk_profile_v2(account_age_days, credit_score, margin_utilization):
    tier = _get_tier(account_age_days, credit_score, margin_utilization)
    config = TIER_CONFIG.get(tier, TIER_CONFIG['HIGH'])  # Safe default
    result = {'risk_tier': tier}
    result.update(config)
    return result

def summarize_tier_benefits(tier_name):
    config = TIER_CONFIG.get(tier_name)
    if config is None:
        return f"Unknown tier: {tier_name}"
    options_str = 'enabled' if config['can_trade_options'] else 'disabled'
    return (f"{tier_name} tier: {config['max_leverage']}x leverage, "
            f"${config['monthly_fee']:.2f}/month, options trading {options_str}")
